@using sv_70e0abfccc92412d907624fbfdd758b8.Services

<div class="message-bubble" @onmouseenter="() => _hovered = true" @onmouseleave="OnMouseLeave">
    <div class="message-header">
        <strong class="message-author">@Message.Author</strong>
        <span class="message-time">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    <ReactionBar Reactions="Message.Reactions" OnReactionClicked="HandleReaction" />

    @if (ThreadReplyCount > 0)
    {
        <button class="thread-link" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)">
            @ThreadReplyCount @(ThreadReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (_hovered)
    {
        <div class="message-actions">
            <button class="action-btn" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)" title="Reply in thread">
                💬 Reply
            </button>
            <button class="action-btn" @onclick="ToggleEmojiPicker" title="Add reaction">
                😀 React
            </button>
        </div>
    }

    @if (_showEmojiPicker)
    {
        <EmojiPicker OnEmojiSelected="HandleEmojiSelected" />
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public int ThreadReplyCount { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnAddReaction { get; set; }

    private bool _hovered;
    private bool _showEmojiPicker;

    private void OnMouseLeave()
    {
        _hovered = false;
        _showEmojiPicker = false;
    }

    private void ToggleEmojiPicker() => _showEmojiPicker = !_showEmojiPicker;

    private async Task HandleReaction(string emoji) =>
        await OnAddReaction.InvokeAsync((Message.Id, emoji));

    private async Task HandleEmojiSelected(string emoji)
    {
        _showEmojiPicker = false;
        await OnAddReaction.InvokeAsync((Message.Id, emoji));
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

@using sv_70e0abfccc92412d907624fbfdd758b8.Services
@inject IJSRuntime JS

<div class="message-list" @ref="_scrollContainer" @onscroll="HandleScroll">
    @if (_loadingMore)
    {
        <div class="loading-indicator">Loading older messages…</div>
    }

    @foreach (var msg in Messages)
    {
        <MessageBubble Message="msg"
                       ThreadReplyCount="GetThreadReplyCount(msg.Id)"
                       OnOpenThread="OnOpenThread"
                       OnAddReaction="OnAddReaction" />
    }
</div>

@code {
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, ThreadSummary> ThreadSummaries { get; set; } = [];
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnAddReaction { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public bool HasMoreMessages { get; set; }

    private ElementReference _scrollContainer;
    private bool _loadingMore;

    private int GetThreadReplyCount(int messageId) =>
        ThreadSummaries.TryGetValue(messageId, out var summary) ? summary.ReplyCount : 0;

    private async Task HandleScroll()
    {
        if (!HasMoreMessages || _loadingMore) return;

        var scrollTop = await JS.InvokeAsync<double>("eval",
            $"document.querySelector('.message-list')?.scrollTop ?? 1");

        if (scrollTop < 50)
        {
            _loadingMore = true;
            await OnLoadMore.InvokeAsync();
            _loadingMore = false;
        }
    }
}

