{"file_text": "/* ===== Layout ===== */

.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
}

.chat-sidebar {
    width: 20%;
    min-width: 200px;
    border-right: 1px solid #e0e0e0;
    background: #2c2f33;
    color: #dcddde;
    overflow-y: auto;
}

.chat-main {
    width: 55%;
    display: flex;
    flex-direction: column;
    background: #fff;
    transition: width 0.2s ease;
}

.chat-main-wide {
    width: 80%;
}

.chat-thread {
    width: 25%;
    min-width: 280px;
    border-left: 1px solid #e0e0e0;
    background: #fafafa;
    overflow: hidden;
}

/* ===== Sidebar ===== */

::deep .channel-sidebar {
    display: flex;
    flex-direction: column;
    height: 100%;
}

::deep .sidebar-header {
    padding: 16px;
    border-bottom: 1px solid #40444b;
}

::deep .sidebar-header h5 {
    margin: 0;
    color: #fff;
    font-size: 1rem;
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

::deep .channel-list {
    overflow-y: auto;
    flex: 1;
    padding: 8px 0;
}

::deep .channel-item {
    padding: 8px 16px;
    cursor: pointer;
    border-radius: 4px;
    margin: 0 8px;
    transition: background 0.15s;
}

::deep .channel-item:hover {
    background: #36393f;
}

::deep .channel-item.active {
    background: #40444b;
}

::deep .channel-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

::deep .channel-name {
    font-weight: 600;
    font-size: 0.95rem;
}

::deep .unread-badge {
    background: #f04747;
    color: #fff;
    font-size: 0.75rem;
    font-weight: 700;
    padding: 1px 6px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

::deep .channel-desc {
    font-size: 0.8rem;
    color: #8e9297;
    margin-top: 2px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

/* ===== Message Area ===== */

::deep .message-area {
    display: flex;
    flex-direction: column;
    height: 100%;
}

::deep .area-header {
    padding: 12px 20px;
    border-bottom: 1px solid #e0e0e0;
    flex-shrink: 0;
}

::deep .area-header h4 {
    margin: 0;
    font-size: 1.1rem;
}

::deep .channel-description {
    margin: 4px 0 0;
    font-size: 0.85rem;
    color: #72767d;
}

::deep .message-list {
    flex: 1;
    overflow-y: auto;
    padding: 12px 20px;
}

::deep .loading-indicator {
    text-align: center;
    padding: 8px;
    color: #72767d;
    font-size: 0.85rem;
}

/* ===== Message Bubble ===== */

::deep .message-bubble {
    padding: 8px 12px;
    border-radius: 6px;
    margin-bottom: 4px;
    position: relative;
    transition: background 0.1s;
}

::deep .message-bubble:hover {
    background: #f2f3f5;
}

::deep .message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
}

::deep .message-author {
    font-size: 0.95rem;
}

::deep .message-time {
    font-size: 0.75rem;
    color: #72767d;
}

::deep .message-content {
    margin: 4px 0;
    font-size: 0.93rem;
    line-height: 1.4;
    color: #2e3338;
}

/* ===== Reactions ===== */

::deep .reaction-bar {
    display: flex;
    gap: 4px;
    margin-top: 4px;
    flex-wrap: wrap;
}

::deep .reaction-badge {
    background: #f0f1f3;
    border: 1px solid #e0e0e0;
    border-radius: 12px;
    padding: 2px 8px;
    font-size: 0.82rem;
    cursor: pointer;
    display: inline-flex;
    align-items: center;
    gap: 3px;
    transition: background 0.15s;
}

::deep .reaction-badge:hover {
    background: #e3e5e8;
    border-color: #c8c9ce;
}

/* ===== Thread Link ===== */

::deep .thread-link {
    background: none;
    border: none;
    color: #5865f2;
    font-size: 0.82rem;
    font-weight: 600;
    cursor: pointer;
    padding: 2px 0;
    margin-top: 2px;
}

::deep .thread-link:hover {
    text-decoration: underline;
}

/* ===== Message Actions (hover) ===== */

::deep .message-actions {
    position: absolute;
    top: -8px;
    right: 8px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #e0e0e0;
    border-radius: 6px;
    padding: 2px 4px;
    box-shadow: 0 1px 4px rgba(0,0,0,0.1);
}

::deep .action-btn {
    background: none;
    border: none;
    font-size: 0.8rem;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
    color: #4f5660;
    white-space: nowrap;
}

::deep .action-btn:hover {
    background: #f2f3f5;
    color: #2e3338;
}

/* ===== Emoji Picker ===== */

::deep .emoji-picker {
    position: absolute;
    top: -44px;
    right: 8px;
    background: #fff;
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    padding: 6px;
    display: flex;
    gap: 2px;
    box-shadow: 0 2px 8px rgba(0,0,0,0.15);
    z-index: 10;
}

::deep .emoji-btn {
    background: none;
    border: none;
    font-size: 1.2rem;
    cursor: pointer;
    padding: 4px 6px;
    border-radius: 4px;
    line-height: 1;
}

::deep .emoji-btn:hover {
    background: #f2f3f5;
}

/* ===== Message Input ===== */

::deep .message-input {
    display: flex;
    gap: 8px;
    padding: 12px 20px;
    border-top: 1px solid #e0e0e0;
    flex-shrink: 0;
    align-items: flex-end;
}

::deep .message-input textarea {
    flex: 1;
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    padding: 10px 14px;
    font-size: 0.93rem;
    resize: none;
    font-family: inherit;
    outline: none;
    transition: border-color 0.15s;
}

::deep .message-input textarea:focus {
    border-color: #5865f2;
}

::deep .send-btn {
    background: #5865f2;
    color: #fff;
    border: none;
    border-radius: 8px;
    padding: 10px 20px;
    font-weight: 600;
    font-size: 0.9rem;
    cursor: pointer;
    white-space: nowrap;
    transition: background 0.15s;
}

::deep .send-btn:hover:not(:disabled) {
    background: #4752c4;
}

::deep .send-btn:disabled {
    background: #a5b0f0;
    cursor: not-allowed;
}

/* ===== Thread Panel ===== */

::deep .thread-panel {
    display: flex;
    flex-direction: column;
    height: 100%;
}

::deep .thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 12px 16px;
    border-bottom: 1px solid #e0e0e0;
    flex-shrink: 0;
}

::deep .thread-header h5 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
}

::deep .close-btn {
    background: none;
    border: none;
    font-size: 1.2rem;
    cursor: pointer;
    color: #72767d;
    padding: 4px 8px;
    border-radius: 4px;
    line-height: 1;
}

::deep .close-btn:hover {
    background: #e0e0e0;
    color: #2e3338;
}

::deep .thread-root-quote {
    padding: 12px 16px;
    border-bottom: 1px solid #e0e0e0;
    background: #f0f1f3;
    flex-shrink: 0;
}

::deep .thread-root-quote strong {
    font-size: 0.9rem;
}

::deep .thread-root-quote p {
    margin: 4px 0 0;
    font-size: 0.88rem;
    color: #4f5660;
}

::deep .thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 8px 16px;
}

::deep .thread-reply {
    padding: 8px 0;
    border-bottom: 1px solid #eee;
}

::deep .thread-reply:last-child {
    border-bottom: none;
}
